import{_ as t,o as r,c as a,ag as o}from"./chunks/framework.CvgP6Fyv.js";const h=JSON.parse('{"title":"Projecten","description":"","frontmatter":{},"headers":[],"relativePath":"nl/features/projects.md","filePath":"nl/features/projects.md"}'),i={name:"nl/features/projects.md"};function n(l,e,s,d,c,p){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="projecten" tabindex="-1">Projecten <a class="header-anchor" href="#projecten" aria-label="Permalink to &quot;Projecten&quot;">​</a></h1><p>Organiseer je werk in projecten om tijd, omzet en winstgevendheid per opdracht bij te houden.</p><h2 id="overzicht" tabindex="-1">Overzicht <a class="header-anchor" href="#overzicht" aria-label="Permalink to &quot;Overzicht&quot;">​</a></h2><p>Projecten helpen je facturen, uitgaven en tijdregistraties te groeperen. Dit geeft je een duidelijk beeld van hoe winstgevend elk project of elke klantopdracht is.</p><h2 id="een-project-aanmaken" tabindex="-1">Een project aanmaken <a class="header-anchor" href="#een-project-aanmaken" aria-label="Permalink to &quot;Een project aanmaken&quot;">​</a></h2><ol><li>Ga naar <strong>Projecten &gt; Nieuw project</strong></li><li>Vul in: <ul><li><strong>Naam</strong> — Een duidelijke projectnaam</li><li><strong>Klant</strong> — De klant waarvoor dit project is</li><li><strong>Omschrijving</strong> — Waar het project over gaat</li><li><strong>Budget</strong> — Optioneel budgetbedrag</li><li><strong>Status</strong> — Actief, In de wacht of Voltooid</li></ul></li><li>Klik op <strong>Opslaan</strong></li></ol><h2 id="projectstatussen" tabindex="-1">Projectstatussen <a class="header-anchor" href="#projectstatussen" aria-label="Permalink to &quot;Projectstatussen&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Status</th><th>Beschrijving</th></tr></thead><tbody><tr><td><strong>Actief</strong></td><td>Er wordt momenteel aan gewerkt</td></tr><tr><td><strong>In de wacht</strong></td><td>Tijdelijk gepauzeerd</td></tr><tr><td><strong>Voltooid</strong></td><td>Afgerond — er wordt geen werk meer verwacht</td></tr><tr><td><strong>Gearchiveerd</strong></td><td>Opgeslagen ter referentie</td></tr></tbody></table><h2 id="projectdetailpagina" tabindex="-1">Projectdetailpagina <a class="header-anchor" href="#projectdetailpagina" aria-label="Permalink to &quot;Projectdetailpagina&quot;">​</a></h2><p>De projectdetailpagina toont:</p><ul><li><strong>Overzicht</strong> — Naam, klant, status, budget</li><li><strong>Gekoppelde facturen</strong> — Alle facturen gerelateerd aan dit project</li><li><strong>Gekoppelde uitgaven</strong> — Kosten toegeschreven aan dit project</li><li><strong>Tijdregistraties</strong> — Uren gelogd voor dit project</li><li><strong>Winstgevendheid</strong> — Omzet versus kosten specificatie</li></ul><h2 id="items-koppelen-aan-projecten" tabindex="-1">Items koppelen aan projecten <a class="header-anchor" href="#items-koppelen-aan-projecten" aria-label="Permalink to &quot;Items koppelen aan projecten&quot;">​</a></h2><p>Bij het aanmaken van facturen, uitgaven of tijdregistraties selecteer je het project uit de dropdown om ze te koppelen. Dit werkt automatisch de financien van het project bij.</p><ul><li><strong>Facturen</strong> — Houd omzet per project bij</li><li><strong>Uitgaven</strong> — Houd kosten per project bij</li><li><strong>Tijdregistraties</strong> — Houd uren per project bij</li></ul><h2 id="budgetopvolging" tabindex="-1">Budgetopvolging <a class="header-anchor" href="#budgetopvolging" aria-label="Permalink to &quot;Budgetopvolging&quot;">​</a></h2><p>Als je een budget instelt:</p><ul><li>Zie hoeveel van het budget is verbruikt</li><li>Houd het resterende budget bij</li><li>Vergelijk werkelijke kosten met het budget</li><li>Ontvang waarschuwingen wanneer je het budgetlimiet nadert</li></ul><h2 id="bulkacties" tabindex="-1">Bulkacties <a class="header-anchor" href="#bulkacties" aria-label="Permalink to &quot;Bulkacties&quot;">​</a></h2><ul><li><strong>Status wijzigen</strong> — Werk meerdere projecten tegelijk bij</li><li><strong>Archiveren</strong> — Verplaats voltooide projecten naar het archief</li><li><strong>Herstellen</strong> — Haal gearchiveerde projecten terug</li></ul><h2 id="rapportages" tabindex="-1">Rapportages <a class="header-anchor" href="#rapportages" aria-label="Permalink to &quot;Rapportages&quot;">​</a></h2><p>Bekijk projectprestaties in de <a href="/nl/features/reports">klantrapportages</a> om te zien:</p><ul><li>Omzet per project</li><li>Bestede tijd per project</li><li>Winstmarges</li><li>Vergelijking tussen projecten</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Gebruik projecten ook voor kleine opdrachten — de inzichten zijn waardevol</li><li>Koppel zowel facturen als uitgaven voor nauwkeurige winstmarges</li><li>Archiveer voltooide projecten om je actieve lijst overzichtelijk te houden</li><li>Bekijk het projectgerichte dashboardprofiel voor een projectfocusweergave</li></ul>',24)])])}const u=t(i,[["render",n]]);export{h as __pageData,u as default};
